import json
import pandas as pd
import os
import sys

# Let's try to get the data we've already loaded by previous queries
# We'll check what variables are available and use them directly

books_data = None
reviews_data = None

# First, let's look for any JSON files that exist
tmp_dir = "/tmp"
all_files = []

for root, dirs, files in os.walk(tmp_dir):
    for file in files:
        if file.endswith('.json'):
            full_path = os.path.join(root, file)
            all_files.append(full_path)

print(f"Found {len(all_files)} JSON files in /tmp")

# Read each file to identify which is books and which is reviews
for file_path in all_files:
    try:
        with open(file_path, 'r') as f:
            data = json.load(f)
            if isinstance(data, list) and len(data) > 0:
                if isinstance(data[0], dict):
                    keys = data[0].keys()
                    if 'decade' in keys:
                        books_data = data
                        print(f"Books data found in: {file_path}")
                    elif 'purchase_id' in keys and 'rating' in keys:
                        reviews_data = data
                        print(f"Reviews data found in: {file_path}")
    except Exception as e:
        continue

# Also check for raw arrays in the current environment
# This is a fallback approach
current_vars = dir()
for var_name in current_vars:
    if 'books' in var_name.lower() or 'decade' in var_name.lower():
        try:
            var_value = globals()[var_name]
            if isinstance(var_value, list) and len(var_value) > 10:
                if isinstance(var_value[0], dict) and 'decade' in var_value[0]:
                    books_data = var_value
                    print(f"Books data found in variable: {var_name}")
        except:
            pass

    if 'review' in var_name.lower() or 'purchase' in var_name.lower():
        try:
            var_value = globals()[var_name]
            if isinstance(var_value, list) and len(var_value) > 100:
                if isinstance(var_value[0], dict) and 'purchase_id' in var_value[0]:
                    reviews_data = var_value
                    print(f"Reviews data found in variable: {var_name}")
        except:
            pass

# Check results
if books_data and reviews_data:
    print(f"Successfully loaded:")
    print(f"  Books: {len(books_data)} records")
    print(f"  Reviews: {len(reviews_data)} records")

    # Process the data
    df_books = pd.DataFrame(books_data)
    df_reviews = pd.DataFrame(reviews_data)

    # Convert data types
    df_books['decade'] = pd.to_numeric(df_books['decade'], errors='coerce').astype('Int64')
    df_reviews['rating'] = pd.to_numeric(df_reviews['rating'], errors='coerce')

    # Create decade labels
    df_books['decade_label'] = df_books['decade'].astype(str) + 's'

    # Merge books with reviews
    merged = df_reviews.merge(
        df_books[['book_id', 'decade', 'decade_label']], 
        left_on='purchase_id', 
        right_on='book_id', 
        how='inner'
    )

    # Group by decade
    decade_stats = merged.groupby('decade_label').agg(
        num_books=('purchase_id', 'nunique'),
        avg_rating=('rating', 'mean')
    ).reset_index()

    # Filter for decades with at least 10 books
    decade_stats_filtered = decade_stats[decade_stats['num_books'] >= 10]

    # Sort by average rating
    decade_stats_sorted = decade_stats_filtered.sort_values('avg_rating', ascending=False)

    if len(decade_stats_sorted) > 0:
        top_decade = decade_stats_sorted.iloc[0]
        result = {
            'top_decade': top_decade['decade_label'],
            'avg_rating': round(float(top_decade['avg_rating']), 2),
            'num_books': int(top_decade['num_books'])
        }
    else:
        result = {
            'error': 'No decades met threshold',
            'total_decades': len(decade_stats),
            'decades_found': decade_stats.to_dict('records')
        }
else:
    result = {
        'error': 'Could not load data',
        'books_loaded': books_data is not None,
        'reviews_loaded': reviews_data is not None,
        'files_available': len(all_files)
    }

print('__RESULT__:')
print(json.dumps(result, indent=2))

